SELECT subject, venue
FROM exams
WHERE exam_id = 1 AND exam_level = 'Final';

SELECT exam_id, COUNT(*) AS report_count
FROM exam_reports
GROUP BY exam_id;

SELECT COUNT(*) AS total_reports
FROM exam_reports
WHERE generated_by = 1001;

SELECT COUNT(*) AS total_exam_records
FROM exams
WHERE exam_year = 2023;

SELECT note
FROM exam_notes
WHERE exam_id = 1;

SELECT DISTINCT exam_id
FROM exams
WHERE exam_year = 2023;
